mapper.update:
UPDATE tbl_schedule
schedule_content = #{scheduleContent}, schedule_price = #{schedulePrice}, schedule_state = #{scheduleState},
WHERE schedule_num = #{scheduleNum}

mapper.select:
SELECT schedule_num, schedule_content, schedule_price, schedule_state, schedule_register_date,
schedule_update_date, schedule_reservation_date FROM tbl_schedule
WHERE schedule_num = #{scheduleNum}
